import boto3

def create_sns_subscription(topic_arn, protocol, endpoint):
    # Create a low-level service client
    sns = boto3.client('sns')

    try:
        response = sns.subscribe(TopicArn=topic_arn, Protocol=protocol, Endpoint=endpoint)
        print("Subscription ARN:", response['SubscriptionArn'])
        
    except Exception as e:
        print("Error occurred while creating subscription.", str(e))
    
if __name__ == "__main__":
    topic_arn = input("Enter Topic ARN: ")
    protocol = 'https' # Protocol is always HTTPS for webhooks 
    endpoint = input("Enter Endpoint URL: ")
    
    create_sns_subscription(topic_arn, protocol, endpoint)